Here's a modern MSTest test class for your `DataFetcher`:

```csharp
[TestClass]
public sealed class DataFetcherTests
{
    private readonly TestContext _testContext;

    public DataFetcherTests(TestContext testContext)
    {
        _testContext = testContext;
    }

    private static HttpClient CreateClient(HttpStatusCode statusCode, string content = "")
    {
        var handler = new FakeHandler(new HttpResponseMessage(statusCode)
        {
            Content = new StringContent(content),
        });
        return new HttpClient(handler);
    }

    [TestMethod]
    [Timeout(5000)]
    public async Task FetchAsync_SuccessResponse_ReturnsContent()
    {
        // Arrange
        var fetcher = new DataFetcher(CreateClient(HttpStatusCode.OK, "hello"));

        // Act
        var result = await fetcher.FetchAsync("https://example.com", _testContext.CancellationToken);

        // Assert
        Assert.AreEqual("hello", result);
    }

    [TestMethod]
    [Timeout(5000)]
    public async Task FetchAsync_NotFound_ThrowsHttpRequestException()
    {
        var fetcher = new DataFetcher(CreateClient(HttpStatusCode.NotFound));

        await Assert.ThrowsExactlyAsync<HttpRequestException>(
            async () => await fetcher.FetchAsync("https://example.com", _testContext.CancellationToken));
    }

    [TestMethod]
    [Timeout(5000)]
    public async Task FetchAsync_CancellationRequested_ThrowsTaskCanceledException()
    {
        using var cts = new CancellationTokenSource();
        cts.Cancel(); // pre-cancel

        var fetcher = new DataFetcher(CreateClient(HttpStatusCode.OK, "data"));

        await Assert.ThrowsExactlyAsync<TaskCanceledException>(
            async () => await fetcher.FetchAsync("https://example.com", cts.Token));
    }

    // Minimal fake handler — no mocking library needed
    private sealed class FakeHandler(HttpResponseMessage response) : HttpMessageHandler
    {
        protected override Task<HttpResponseMessage> SendAsync(
            HttpRequestMessage request, CancellationToken cancellationToken)
        {
            cancellationToken.ThrowIfCancellationRequested();
            return Task.FromResult(response);
        }
    }
}
```

**Key patterns used:**

| Pattern | How |
|---|---|
| **Sealed class** | `public sealed class` for perf & clarity |
| **Constructor-injected TestContext** | Gives access to `_testContext.CancellationToken` |
| **Timeout + CancellationToken** | `[Timeout(5000)]` auto-cancels via `TestContext.CancellationToken` — always pass it to async calls |
| **Cancellation testing** | Pre-cancel a `CancellationTokenSource`, assert `TaskCanceledException` |
| **Exception testing** | `Assert.ThrowsExactlyAsync` instead of `[ExpectedException]` |
| **No mocking library** | Lightweight `FakeHandler` controls `HttpClient` responses directly |

The critical insight: `[Timeout]` fires `TestContext.CancellationToken` when time expires, so always forward it into your async calls. For cancellation tests, use a separate pre-cancelled `CancellationTokenSource` instead.
